import * as React from 'react';
import './styles.css';

export default function StaticHello(): React.JSX.Element {
  const [greeting, setGreeting] = React.useState<string>('');

  const handleButtonClick = (): void => {
    setGreeting('Hello from the legacy web part!');
  };

  return (
    <div id="greeting-box">
      <img src="logo.svg" alt="Team logo" />
      <h2 id="greeting-title">Team Directory</h2>
      <button id="load-button" onClick={handleButtonClick}>
        Load greeting
      </button>
      <p id="greeting-output">{greeting}</p>
    </div>
  );
}
